// WhatsApp Webhook Message Parser
// Normalizes incoming webhook payload into standard format { phone, message_type, message_body, media_id, is_media, timestamp }

const rawData = $input.first().json;

// 1) Check for WhatsApp Cloud API GET verification handshake
// In n8n, GET query params may appear directly or nested under "query"
const hubMode = rawData.hub?.mode || rawData.query?.hub?.mode || '';
const hubToken = rawData.hub?.['verify_token'] || rawData.query?.hub?.['verify_token'] || '';
const hubChallenge = rawData.hub?.challenge || rawData.query?.hub?.challenge || '';

if (hubMode === 'subscribe') {
  const expectedToken = process.env.WHATSAPP_VERIFY_TOKEN || '';
  const verified = hubToken === expectedToken;
  return [
    {
      json: {
        isVerification: true,
        verified: verified,
        challenge: verified ? hubChallenge : 'Verification failed - token mismatch'
      }
    }
  ];
}

// 2) Check for POST with WhatsApp message payload
if (rawData.entry && Array.isArray(rawData.entry) && rawData.entry.length > 0) {
  const entry = rawData.entry[0];
  if (entry.changes && Array.isArray(entry.changes) && entry.changes.length > 0) {
    const change = entry.changes[0];
    const value = change.value || {};

    // Discard status updates (no messages array)
    if (!value.messages || !Array.isArray(value.messages) || value.messages.length === 0) {
      return [
        {
          json: {
            isStatusUpdate: true
          }
        }
      ];
    }

    const msg = value.messages[0];
    const contact = value.contacts && value.contacts.length > 0 ? value.contacts[0] : null;
    const messageType = msg.type || 'text';

    // Extract message body based on type
    let messageBody = '';
    let mediaId = '';

    if (messageType === 'text' && msg.text) {
      messageBody = msg.text.body || '';
    } else if (messageType === 'image' && msg.image) {
      messageBody = msg.image.caption || '';
      mediaId = msg.image.id || '';
    } else if (messageType === 'document' && msg.document) {
      messageBody = msg.document.caption || '';
      mediaId = msg.document.id || '';
    } else if (messageType === 'audio' && msg.audio) {
      mediaId = msg.audio.id || '';
    } else if (messageType === 'video' && msg.video) {
      mediaId = msg.video.id || '';
    }

    return [
      {
        json: {
          isVerification: false,
          isStatusUpdate: false,
          phone: msg.from || '',
          message_type: messageType,
          message_body: messageBody,
          media_id: mediaId,
          is_media: messageType !== 'text',
          message_id: msg.id || '',
          timestamp: msg.timestamp || String(Math.floor(Date.now() / 1000)),
          profile_name: contact ? contact.profile?.name || '' : ''
        }
      }
    ];
  }
}

// 3) Unknown payload format — treat as status update to avoid errors
return [
  {
    json: {
      isStatusUpdate: true
    }
  }
];

// Session Manager
// Reads/writes sessions via n8n Data Store ($dataStore)
// Key: session:{phone}, TTL: 1800 (30 minutes)
// Creates new session with state:START if none exists
// If expired (30min) → delete and re-create

const data = $input.first().json;

// Pass through verification and status updates (no session needed)
if (data.isVerification) {
  return [{ json: { ...data, session: null } }];
}
if (data.isStatusUpdate) {
  return [{ json: { ...data, session: null } }];
}

const phone = data.phone;
if (!phone) {
  return [{ json: { ...data, session: null, error: 'No phone number provided' } }];
}

const sessionKey = `session:${phone}`;

// Try to load existing session from Data Store
let session = null;
try {
  session = await $dataStore.get(sessionKey);
} catch (e) {
  // Data Store unavailable or key doesn't exist
  session = null;
}

const now = new Date();

// If session exists, check expiry (30 minutes)
if (session) {
  const updatedAt = new Date(session.updated_at).getTime();
  const thirtyMinutesAgo = now.getTime() - (30 * 60 * 1000);

  if (updatedAt < thirtyMinutesAgo) {
    // Session expired — delete and re-create
    try {
      await $dataStore.delete(sessionKey);
    } catch (e) {
      // Ignore deletion errors
    }
    session = null;
  }
}

// Create new session if none exists or was expired
if (!session) {
  session = {
    phone: phone,
    name: '',
    email: '',
    state: 'START',
    participant_id: '',
    photo_id: '',
    photo_url: '',
invoice_data: {},
purchase_id: '',
entry_id: '',
points_earned: 0,
points_awarded: 0,
total_points: 0,

    retry_count: 0,
    created_at: now.toISOString(),
    updated_at: now.toISOString()
  };

  try {
    await $dataStore.set(sessionKey, session, { ttl: 1800 });
  } catch (e) {
    console.error('Failed to create session:', e);
  }
} else {
  // Update timestamp to keep session alive
  session.updated_at = now.toISOString();
  try {
    await $dataStore.set(sessionKey, session, { ttl: 1800 });
  } catch (e) {
    console.error('Failed to update session:', e);
  }
}

return [
  {
    json: {
      ...data,
      session: session,
      sessionKey: sessionKey
    }
  }
];

// Welcome Handler
// START state: send welcome message and transition to WAIT_PHONE

const data = $input.first().json;

if (!data.session) {
  return [{ json: { ...data, replyMessage: '', action: 'noop' } }];
}

// Update session: state → WAIT_PHONE, reset retry
const session = { ...data.session };
session.state = 'WAIT_PHONE';
session.retry_count = 0;
session.updated_at = new Date().toISOString();

return [
  {
    json: {
      ...data,
      session: session,
      replyMessage: 'Bienvenido a Superlikers. Para participar en nuestra promocion, por favor indica tu numero de telefono a 10 digitos.',
      action: 'welcome'
    }
  }
];

// Phone Validator
// Output 0: valid phone number → continues to Search Participant
// Output 1: invalid phone number → routes to error handling
// Validates: 10 digits (Colombia), strips non-numeric, normalizes with COUNTRY_CODE prefix

const COUNTRY_CODE = process.env.COUNTRY_CODE || '57';
const PHONE_DIGITS = parseInt(process.env.PHONE_DIGITS || '10', 10);

const data = $input.first().json;
let rawPhone = data.message_body || '';

// Strip all non-numeric characters
const digits = rawPhone.replace(/\D/g, '');

if (digits.length !== PHONE_DIGITS) {
  // INVALID — output 1
  return [
    [],
    [
      {
        json: {
          ...data,
          valid: false,
          phone: null,
          normalizedPhone: null,
          error: `El numero debe tener exactamente ${PHONE_DIGITS} digitos. Recibimos ${digits.length} digitos. Intenta de nuevo.`
        }
      }
    ]
  ];
}

// VALID — output 0
const normalizedPhone = `+${COUNTRY_CODE}${digits}`;

return [
  [
    {
      json: {
        ...data,
        valid: true,
        phone: normalizedPhone,
        normalizedPhone: normalizedPhone,
        rawInput: rawPhone
      }
    }
  ],
  []
];

// Session Update
// Applies partial updates to session and persists to Data Store
// Resets retry_count on state change
// Saves with TTL 1800

const data = $input.first().json;

// Pass through verification and status updates
if (data.isVerification || data.isStatusUpdate) {
  return [{ json: data }];
}

let session = data.session ? { ...data.session } : null;
if (!session) {
  return [{ json: data }];
}

const phone = data.normalizedPhone || data.phone || session.phone || '';
const sessionKey = `session:${phone}`;

// Determine what updates to apply based on action + context
const previousState = session.state;

if (data.action === 'welcome') {
  // Welcome Handler already updated state to WAIT_PHONE — persist
} else if (data.valid === false) {
  // Phone validation failed — increment retry, keep current state
  session.retry_count = (session.retry_count || 0) + 1;
} else if (data.valid === true && phone) {
  // Phone validated successfully — update phone, stay in current state
  session.phone = phone;
  // State changes happen AFTER the HTTP search, not here
  } else if (data.statusCode === 200 && data.body && data.body.photo_id) {
    // Ticket upload success
    const result = typeof data.body === 'object' ? data.body : {};
    session.photo_id = result.photo_id || '';
    session.photo_url = result.url || '';
    session.state = 'UPLOAD_TICKET';
    session.retry_count = 0;
  } else if (data.statusCode === 200 && data.body) {
  // Participant found via API
  const participant = typeof data.body === 'object' ? data.body : {};
  session.state = 'WAIT_TICKET';
  session.retry_count = 0;
  session.participant_id = participant.id || participant.participant_id || '';
  session.name = participant.name || '';
  session.email = participant.email || '';
  session.phone = phone || session.phone;
} else if (data.statusCode === 404) {
  // Participant not found — proceed to registration flow
  session.state = 'WAIT_NAME';
  session.retry_count = 0;
} else if (data.statusCode >= 400) {
  // API error (500, 429, etc.) — increment retry, keep state
  session.retry_count = (session.retry_count || 0) + 1;
} else if (data.action === 'name_captured') {
  // Name captured — store name, transition to WAIT_EMAIL
  session.name = data.name || '';
  session.state = 'WAIT_EMAIL';
} else if (data.action === 'email_captured') {
  // Email captured — store email, transition to WAIT_CONFIRMATION
  session.email = data.email || '';
  session.state = 'WAIT_CONFIRMATION';
} else if (data.action === 'confirmed') {
  // User confirmed data — proceed to registration
  session.state = 'REGISTER_PARTICIPANT';
} else if (data.action === 'cancelled') {
  // User cancelled — reset registration data, go back to WAIT_NAME
  session.state = 'WAIT_NAME';
  session.name = '';
  session.email = '';
  session.retry_count = 0;
} else if (data.statusCode === 201 && data.body && data.body.purchase_id) {
  // Purchase registered successfully
  session.purchase_id = data.body.purchase_id;
  session.points_earned = data.body.points_earned || 0;
  session.state = 'REGISTER_PURCHASE';
} else if (data.statusCode === 201 && data.body) {
  // Participant created successfully via API
  const participant = typeof data.body === 'object' ? data.body : {};
  session.state = 'WAIT_TICKET';
  session.retry_count = 0;
  session.participant_id = participant.id || participant.participant_id || '';
  session.name = participant.name || session.name || '';
  session.email = participant.email || session.email || '';
  session.phone = participant.phone || session.phone || '';
  session.replyMessage = data.replyMessage || 'Registrado exitosamente. Ahora envia una foto de tu ticket.';
}


} else if (data.action === 'invoice_valid' && data.invoice_data) {
  // Invoice extracted successfully
  session.invoice_data = data.invoice_data;
  session.state = 'PROCESS_INVOICE';
} else if (data.action === 'invoice_invalid') {
  // Invoice extraction failed — retry
  session.state = 'WAIT_TICKET';
  session.retry_count = (session.retry_count || 0) + 1;
} else if (data.statusCode === 409 && data.body && data.body.existing_purchase_id) {
  // Duplicate purchase — use existing_purchase_id
  session.purchase_id = data.body.existing_purchase_id;
  session.state = 'REGISTER_PURCHASE';
} else if (data.statusCode === 200 && data.body && data.body.entry_id) {
  // Entry accepted — store points
  session.entry_id = data.body.entry_id;
  session.points_awarded = data.body.points_awarded || 0;
  session.total_points = data.body.total_points || 0;
  session.state = 'ACCEPT_ENTRY';
} else if (data.action === 'finished') {
  // Pipeline complete
  session.state = 'FINISHED';

// Reset retry_count on state change
if (session.state !== previousState && previousState) {
  session.retry_count = 0;
}

// Always update timestamp
session.updated_at = new Date().toISOString();

// Persist to Data Store
if (phone) {
  try {
    await $dataStore.set(sessionKey, session, { ttl: 1800 });
  } catch (e) {
    console.error('Failed to update session in Data Store:', e);
  }
}

return [
  {
    json: {
      ...data,
      session: session
    }
  }
];

// Message Builder
// Builds WhatsApp message payload from the current state and context
// Returns: { to, type, text: { body } }
// This is the last node in the chain — its output becomes the webhook response

const data = $input.first().json;

// 1) Handle GET verification — return challenge as plain text response
if (data.isVerification) {
  return [
    {
      json: {
        to: '',
        type: 'text',
        text: {
          body: data.challenge || 'Verification failed'
        }
      }
    }
  ];
}

// 2) Handle status updates — return empty 200
if (data.isStatusUpdate) {
  return [
    {
      json: {
        to: '',
        type: 'none',
        text: {
          body: 'ok'
        }
      }
    }
  ];
}

const phone = data.normalizedPhone || data.phone || '';
const session = data.session || {};

// 3) Use explicit replyMessage if set by a handler
let replyBody = data.replyMessage || '';

// 4) If no replyMessage was set, generate based on session state
if (!replyBody && session.state) {
  switch (session.state) {
    case 'WAIT_PHONE':
      replyBody = 'Por favor indica tu numero de telefono a 10 digitos.';
      break;
    case 'WAIT_NAME':
      replyBody = 'No encontramos tu registro. Por favor indicame tu nombre completo.';
      break;
    case 'WAIT_EMAIL':
      replyBody = 'Gracias. Ahora indicame tu correo electronico.';
      break;
    case 'WAIT_CONFIRMATION':
      replyBody = `Confirma que tus datos son correctos:\nNombre: ${session.name || ''}\nEmail: ${session.email || ''}\n\nResponde Si o No.`;
      break;
    case 'UPLOAD_TICKET':
      replyBody = 'Gracias, hemos recibido tu foto de ticket. Estamos procesando la informacion...';
      break;

    case 'WAIT_TICKET':
      replyBody = 'Ya encontramos tu registro. Por favor enviame una foto de tu ticket de compra. Solo aceptamos imagenes en formato JPEG o PNG.';
      break;
    case 'PROCESS_INVOICE':
  replyBody = 'Estamos procesando la informacion de tu ticket...';
  break;
case 'REGISTER_PURCHASE':
  replyBody = 'Registrando tu compra...';
  break;
case 'ACCEPT_ENTRY':
  replyBody = 'Confirmando tu participacion...';
  break;
case 'FINISHED':
  replyBody = data.replyMessage || 'Proceso completado. Gracias por participar.';
  break;
case 'ERROR':
  replyBody = data.replyMessage || 'Ocurrio un error. Por favor intenta de nuevo.';
  break;
    default:
      replyBody = 'Gracias por tu mensaje. Te responderemos pronto.';
  }
}

// 5) If there was an error (phone validation, etc.), use it
if (!replyBody && data.error) {
  replyBody = data.error;
}

return [
  {
    json: {
      to: phone,
      type: 'text',
      text: {
        body: replyBody || 'Gracias por tu mensaje. Te responderemos pronto.'
      }
    }
  }
];

// Name Handler
// Captures user's name, validates, transitions to WAIT_EMAIL
// Output 0: valid name
// Output 1: invalid name

const data = $input.first().json;
const name = (data.message_body || '').trim();

// Validate: min 3 chars, only letters and spaces (incl. accents)
const validName = /^[a-zA-Z\\u00E0-\\u00FC\\u00D1\\u00F1\\s]+$/.test(name);

if (!name || name.length < 3 || !validName) {
  // Invalid name — output 1: stay in WAIT_NAME
  const session = data.session ? {...data.session} : {};
  session.retry_count = (session.retry_count || 0) + 1;
  return [
    [],
    [{
      json: {
        ...data,
        session,
        action: 'invalid_name',
        replyMessage: 'Por favor ingresa un nombre valido (minimo 3 caracteres, solo letras y espacios).'
      }
    }]
  ];
}

// Valid name — output 0: transition to WAIT_EMAIL
const session = data.session ? {...data.session} : {};
session.name = name;
session.state = 'WAIT_EMAIL';
session.retry_count = 0;

return [
  [{
    json: {
      ...data,
      session,
      name,
      action: 'name_captured',
      replyMessage: `Gracias ${name}. Ahora indicame tu correo electronico.`
    }
  }],
  []
];

// Email Validator
// Captures user's email, validates format, transitions to WAIT_CONFIRMATION
// Output 0: valid email
// Output 1: invalid email

const data = $input.first().json;
const email = (data.message_body || '').trim().toLowerCase();

// Validate email format
const emailRegex = /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/;

if (!email || !emailRegex.test(email)) {
  // Invalid email — output 1: stay in WAIT_EMAIL
  const session = data.session ? {...data.session} : {};
  session.retry_count = (session.retry_count || 0) + 1;
  return [
    [],
    [{
      json: {
        ...data,
        session,
        action: 'invalid_email',
        replyMessage: 'El correo ingresado no es valido. Por favor ingresa un correo electronico valido (ejemplo: nombre@correo.com).'
      }
    }]
  ];
}

// Valid email — output 0: transition to WAIT_CONFIRMATION with summary
const session = data.session ? {...data.session} : {};
session.email = email;
session.state = 'WAIT_CONFIRMATION';
session.retry_count = 0;

return [
  [{
    json: {
      ...data,
      session,
      email,
      action: 'email_captured',
      replyMessage: `Confirma que tus datos son correctos:\\nNombre: ${session.name || ''}\\nEmail: ${email}\\n\\nResponde Si o No.`
    }
  }],
  []
];

// Confirmation Handler
// Parses user response (Sí/No) at WAIT_CONFIRMATION
// Output 0: Sí → REGISTER_PARTICIPANT
// Output 1: No → reset to WAIT_NAME
// Output 2: fallback → stay WAIT_CONFIRMATION

const data = $input.first().json;
const response = (data.message_body || '').trim().toLowerCase();

const yesVariants = ['sí', 'si', 'yes', 'dale', 'ok', 'confirmo', 'confirmar', 'correcto'];
const noVariants = ['no', 'nop', 'cancelar', 'cancel', 'cancelar registro'];

let session = data.session ? {...data.session} : {};

if (yesVariants.includes(response)) {
  // Sí — output 0: proceed to registration
  session.state = 'REGISTER_PARTICIPANT';
  session.retry_count = 0;
  return [
    [{
      json: {
        ...data,
        session,
        action: 'confirmed',
        replyMessage: 'Gracias. Estamos registrando tus datos...'
      }
    }],
    [],
    []
  ];
}

if (noVariants.includes(response)) {
  // No — output 1: reset to WAIT_NAME, clear data
  session.state = 'WAIT_NAME';
  session.name = '';
  session.email = '';
  session.retry_count = 0;
  return [
    [],
    [{
      json: {
        ...data,
        session,
        action: 'cancelled',
        replyMessage: 'OK, empecemos de nuevo. Por favor indicame tu nombre completo.'
      }
    }],
    []
  ];
}

// Unrecognized — output 2: stay WAIT_CONFIRMATION, retry prompt
session.retry_count = (session.retry_count || 0) + 1;
return [
  [],
  [],
  [{
    json: {
      ...data,
      session,
      action: 'unclear_confirmation',
      replyMessage: `No entendi tu respuesta. Responde Si si los datos son correctos, o No para reiniciar.\\n\\nNombre: ${session.name || ''}\\nEmail: ${session.email || ''}`
    }
  }]
];

// Invoice Validator
// Validates OpenAI Vision response
// Output 0: valid (confidence >= 0.7, required fields present)
// Output 1: invalid (low confidence or missing fields)

const data = $input.first().json;
const body = data.body || {};
const choices = body.choices || [];

if (choices.length === 0) {
  // No response from AI
  return [[], [{ json: { ...data, action: 'invoice_invalid', error: 'No se pudo procesar la imagen. Intenta con una foto mas clara.' } }]];
}

let invoiceData;
try {
  const content = choices[0].message?.content || '{}';
  invoiceData = JSON.parse(content);
} catch (e) {
  return [[], [{ json: { ...data, action: 'invoice_invalid', error: 'No se pudieron extraer los datos de la factura. Intenta de nuevo.' } }]];
}

const confidence = invoiceData.confidence_score || 0;
const hasRequired = invoiceData.amount && invoiceData.merchant_name && invoiceData.date;

if (confidence >= 0.7 && hasRequired) {
  // VALID — output 0
  return [[{ json: { ...data, invoice_data: invoiceData, action: 'invoice_valid' } }], []];
} else {
  // INVALID — output 1
  const reason = !hasRequired ? 'faltan campos requeridos' : 'confianza baja (' + confidence + ')';
  return [[], [{ json: { ...data, action: 'invoice_invalid', invoice_data: invoiceData, error: 'No se pudieron verificar los datos de la factura. ' + reason + '. Intenta con una foto mas clara.' } }]];
}

// Points Builder
// Builds final FINISHED message with points summary

const data = $input.first().json;
const body = data.body || {};
const pointsAwarded = body.points_awarded || 0;
const totalPoints = body.total_points || 0;

const session = data.session ? { ...data.session } : {};
session.state = 'FINISHED';
session.retry_count = 0;

const replyMessage = '¡Felicidades! Has completado el proceso.

Puntos ganados en esta compra: ' + pointsAwarded + '
Total de puntos acumulados: ' + totalPoints + '

Gracias por participar en la promocion de Superlikers. 🎉';

return [{
  json: {
    ...data,
    session,
    points_awarded: pointsAwarded,
    total_points: totalPoints,
    action: 'finished',
    replyMessage: replyMessage
  }
}];
